using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ── AddItem ────────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
        _cart.AddItem("SKU-002", 3, 4.50m);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
        _cart.AddItem("SKU-001", 2, 9.99m);
    }

    // ── RemoveItem ─────────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
        _cart.RemoveItem("SKU-001");
    }

    [TestMethod]
    public void RemoveItem_AfterRemoval_ItemNotInTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 1, 5.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(5.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_AllItems_TotalIsZero()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    // ── CalculateTotal ─────────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsPriceTimesQuantity()
    {
        _cart.AddItem("SKU-001", 3, 5.00m);

        Assert.AreEqual(15.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfLineItems()
    {
        _cart.AddItem("SKU-001", 2, 10.00m);
        _cart.AddItem("SKU-002", 1, 7.50m);

        Assert.AreEqual(27.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_CalledMultipleTimes_ReturnsSameResult()
    {
        _cart.AddItem("SKU-001", 1, 12.00m);

        var first = _cart.CalculateTotal();
        var second = _cart.CalculateTotal();

        Assert.AreEqual(first, second);
    }

    // ── ApplyCoupon ────────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 50.00m);
        _cart.ApplyCoupon("SAVE10");
    }

    [TestMethod]
    public void ApplyCoupon_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        var totalBefore = _cart.CalculateTotal();

        _cart.ApplyCoupon("SAVE10");
        var totalAfter = _cart.CalculateTotal();

        Assert.IsTrue(totalAfter < totalBefore,
            "Total after coupon should be less than total before coupon.");
    }

    // ── Integration / end-to-end scenarios ─────────────────────

    [TestMethod]
    public void FullWorkflow_AddRemoveCouponTotal_ProducesExpectedResult()
    {
        _cart.AddItem("SKU-001", 2, 25.00m);
        _cart.AddItem("SKU-002", 1, 10.00m);
        _cart.RemoveItem("SKU-002");
        _cart.ApplyCoupon("SAVE10");

        var total = _cart.CalculateTotal();

        Assert.IsTrue(total < 50.00m,
            "After removing an item and applying a coupon the total should be reduced.");
    }

    [TestMethod]
    public void AddItem_AfterCalculateTotal_UpdatesTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        var first = _cart.CalculateTotal();

        _cart.AddItem("SKU-002", 1, 5.00m);
        var second = _cart.CalculateTotal();

        Assert.AreEqual(first + 5.00m, second);
    }
}

